#include<bits/stdc++.h>
using namespace std;
const long long N=4010,M=100010;
long long head[N],now[N],tot=1,d[N],n,m,s,t;
bool vis[N];
struct edge
{
    long long to,flow,nxt;
}e[M];
void add1(long long u,long long v,long long w)
{
    e[++tot]={v,w,head[u]};
    head[u]=tot;
}
void add(long long u,long long v,long long w)
{
    add1(u,v,w);
    add1(v,u,0);
}
bool bfs()
{
    memset(d,0,sizeof(d));
    d[s]=1;
    queue<long long> q;
    q.push(s);
    while(!q.empty())
    {
        long long t=q.front();
        q.pop();
        for(long long i=head[t];i;i=e[i].nxt)
        {
            long long v=e[i].to,val=e[i].flow;
            if(val&&!d[v])
            {
                d[v]=d[t]+1;
                if(v==::t)
                {
                    return true;
                }
                q.push(v);
            }
        }
    }
    return false;
}
long long dfs(long long x,long long flow)
{
    if(x==t||flow==0)
    {
        return flow;
    }
    long long sum=0;
    for(long long i=now[x];i;i=e[i].nxt)
    {
        now[x]=i;
        long long v=e[i].to;
        if(d[v]==d[x]+1&&e[i].flow)
        {
            long long tmp=dfs(v,min(flow,e[i].flow));
            e[i].flow-=tmp;
            e[i^1].flow+=tmp;
            sum+=tmp;
            flow-=tmp;
            if(flow==0)
            {
                break;
            }
        }
    }
    if(sum==0)
    {
        d[x]=0;
    }
    return sum;
}
long long dinic()
{
    long long ans=0;
    while(bfs())
    {
        memcpy(now,head,sizeof(head));
        ans+=dfs(s,2e9);
    }
    return ans;
}
long long res[1010][1010];
int main()
{
    scanf("%lld%lld",&n,&m);
    s=n*2+1;
    t=s+1;
    long long sum=0;
    for(int i=1;i<=n;i++)
    {
        int x;
        scanf("%d",&x);
        add(s,i,x);
        add(i,i+n,1e9);
    }
    for(int i=1;i<=n;i++)
    {
        int x;
        scanf("%d",&x);
        sum+=x;
        add(i+n,t,x);
    }
    for(int i=1;i<=m;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        add(x,y+n,1e9);
        add(y,x+n,1e9);
    }
    long long ans=dinic();
    if(ans<sum)
    {
        printf("NO");
        return 0;
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=head[i];j;j=e[j].nxt)
        {
            int v=e[j].to;
            if(v>n*2||v<=n)
            {
                continue;
            }
            int val=1e9-e[j].flow;
            res[i][v-n]+=val;
        }
    }
    printf("YES\n");
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)
        {
            printf("%lld ",res[i][j]);
        }
        printf("\n");
    }
    return 0;
}
